export const getGetFlightPassengersUrl = (flightNumber: string,
    params: GetFlightPassengersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/flights/${flightNumber}/passengers?${stringifiedParams}` : `/api/flights/${flightNumber}/passengers`
}

